istsSync(dbPath)) {\n45:   console.error(`opencode.db not found at: ${dbPath}`);\n46:   process.exit(1);\n47: }\n48: \n49: const db = new DatabaseSync(dbPath);\n50: \n51: const localProject = db.prepare(\n52:   ''SELECT id FROM project WHERE worktree = ?''\n53: ).get(worktree);\n54: \n55: let localProjectId;\n56: if (localProject) {\n57:   localProjectId = localProject.id;\n58: } else {\n59:   localProjectId = crypto.createHash(''sha1'').update(worktree).digest(''hex'');\n60:   console.log(`Project not found locally, will create with id: ${localProjectId}`);\n61: }\n62: \n63: db.close();\n64: \n65: sql = replaceAll(sql, ''{{WORKTREE}}'', worktree);\n66: sql = replaceAll(sql, ''{{WORKTREE}}''.replace(/\\//g, ''\\\\\\\\''), worktree.replace(/\\//g, ''\\\\''));\n67: sql = replaceAll(sql, ''{{PROJECT_ID}}'', localProjectId);\n68: \n69: const insertCount = (sql.match(/^INSERT /gm) || []).length;\n70: \n71: console.log(JSON.stringify({\n72:   mode,\n73:   local_worktree: worktree,\n74:   local_project_id: localProjectId,\n75:   insert_count: insertCount,\n76:   header: headerLines.map(l => l.replace(/^-- /, '''')),\n77: }, null, 2));\n78: \n79: if (mode === ''dry-run'') {\n80:   console.log(''\\n[DRY RUN] No changes made. Use --yes to execute.'');\n81:   process.exit(0);\n82: }\n83: \n84: const importDb = new DatabaseSync(dbPath);\n85: importDb.exec(''PRAGMA foreign_keys = OFF'');\n86: importDb.exec(''BEGIN TRANSACTION'');\n87: try {\n88:   importDb.exec(sql);\n89:   importDb.exec(`\n90:     UPDATE event_sequence\n91:     SET seq = (SELECT MAX(e.seq) FROM event e WHERE e.aggregate_id = event_sequence.aggregate_id)\n92:     WHERE aggregate_id IN (\n93:       SELECT es.aggregate_id FROM event_sequence es\n94:       JOIN event e ON e.aggregate_id = es.aggregate_id\n95:       GROUP BY es.aggregate_id\n96:       HAVING es.seq < MAX(e.seq)\n97:     )\n98:   `);\n99:   importDb.exec(''COMMIT'');\n100:   importDb.exec(''PRAGMA foreign_keys = ON'');\n101:   console.log(`\\nImport completed: ${insertCount} INSERT statements executed.`);\n102: } catch (err) {\n103:   try { importDb.exec(''ROLLBACK''); } catch {}\n104:   try { importDb.exec(''PRAGMA foreign_keys = ON''); } catch {}\n105:   console.error(`Import failed: ${err.message}`);\n106:   process.exit(1);\n107: }\n108: \n109: function replaceAll(str, search, replacement) {\n110:   if (!search) return str;\n111:   return str.split(search).join(replacement);\n112: }\n\n(End of file - total 112 lines)\n</content>","metadata":{"preview":"#!/usr/bin/env node\nconst { DatabaseSync } = require(''node:sqlite'');\nconst fs = require(''fs'');\nconst path = require(''path'');\nconst { execSync } = require(''child_process'');\nconst os = require(''os'');\nconst crypto = require(''crypto'');\n\nlet mode = null;\nlet projectDir = null;\n\nfor (const arg of process.argv.slice(2)) {\n  if (arg === ''--dry-run'') mode = ''dry-run'';\n  else if (arg === ''--yes'') mode = ''yes'';\n  else projectDir = path.resolve(arg);\n}\n\nif (!mode) {\n  console.error(''Usage: node import_conversations.js [--dry-run|--yes] [project_dir]'');\n  console.error(''  --dry-run  Preview import without making changes'');","truncated":false,"loaded":[],"display":{"type":"file","path":"{{WORKTREE}}\\scripts\\import_conversations.js","text":"#!/usr/bin/env node\nconst { DatabaseSync } = require(''node:sqlite'');\nconst fs = require(''fs'');\nconst path = require(''path'');\nconst { execSync } = require(''child_process'');\nconst os = require(''os'');\nconst crypto = require(''crypto'');\n\nlet mode = null;\nlet projectDir = null;\n\nfor (const arg of process.argv.slice(2)) {\n  if (arg === ''--dry-run'') mode = ''dry-run'';\n  else if (arg === ''--yes'') mode = ''yes'';\n  else projectDir = path.resolve(arg);\n}\n\nif (!mode) {\n  console.error(''Usage: node import_conversations.js [--dry-run|--yes] [project_dir]'');\n  console.error(''  --dry-run  Preview import without making changes'');\n  console.error(''  --yes      Execute the import'');\n  process.exit(1);\n}\n\nif (!projectDir) projectDir = process.cwd();\n\nconst worktree = projectDir.replace(/\\\\/g, ''/'');\nconst sqlPath = path.join(projectDir, ''.opencode'', ''conversations.sql'');\n\nif (!fs.existsSync(sqlPath)) {\n  console.error(`SQL file not found: ${sqlPath}`);\n  process.exit(1);\n}\n\nlet sql = fs.readFileSync(sqlPath, ''utf8'');\nconst headerLines = sql.split(''\\n'').filter(l => l.startsWith(''-- ''));\n\nif (!headerLines.some(l => l.includes(''OPENCODE_CONVERSATION_BACKUP''))) {\n  console.error(''Invalid SQL file: missing backup header'');\n  process.exit(1);\n}\n\nconst dbPath = path.join(os.homedir(), ''.local'', ''share'', ''opencode'', ''opencode.db'');\nif (!fs.existsSync(dbPath)) {\n  console.error(`opencode.db not found at: ${dbPath}`);\n  process.exit(1);\n}\n\nconst db = new DatabaseSync(dbPath);\n\nconst localProject = db.prepare(\n  ''SELECT id FROM project WHERE worktree = ?''\n).get(worktree);\n\nlet localProjectId;\nif (localProject) {\n  localProjectId = localProject.id;\n} else {\n  localProjectId = crypto.createHash(''sha1'').update(worktree).digest(''hex'');\n  console.log(`Project not found locally, will create with id: ${localProjectId}`);\n}\n\ndb.close();\n\nsql = replaceAll(sql, ''{{WORKTREE}}'', worktree);\nsql = replaceAll(sql, ''{{WORKTREE}}''.replace(/\\//g, ''\\\\\\\\''), worktree.replace(/\\//g, ''\\\\''));\nsql = replaceAll(sql, ''{{PROJECT_ID}}'', localProjectId);\n\nconst insertCount = (sql.match(/^INSERT /gm) || []).length;\n\nconsole.log(JSON.stringify({\n  mode,\n  local_worktree: worktree,\n  local_project_id: localProjectId,\n  insert_count: insertCount,\n  header: headerLines.map(l => l.replace(/^-- /, '''')),\n}, null, 2));\n\nif (mode === ''dry-run'') {\n  console.log(''\\n[DRY RUN] No changes made. Use --yes to execute.'');\n  process.exit(0);\n}\n\nconst importDb = new DatabaseSync(dbPath);\nimportDb.exec(''PRAGMA foreign_keys = OFF'');\nimportDb.exec(''BEGIN TRANSACTION'');\ntry {\n  importDb.exec(sql);\n  importDb.exec(`\n    UPDATE event_sequence\n    SET seq = (SELECT MAX(e.seq) FROM event e WHERE e.aggregate_id = event_sequence.aggregate_id)\n    WHERE aggregate_id IN (\n      SELECT es.aggregate_id FROM event_sequence es\n      JOIN event e ON e.aggregate_id = es.aggregate_id\n      GROUP BY es.aggregate_id\n      HAVING es.seq < MAX(e.seq)\n    )\n  `);\n  importDb.exec(''COMMIT'');\n  importDb.exec(''PRAGMA foreign_keys = ON'');\n  console.log(`\\nImport completed: ${insertCount} INSERT statements executed.`);\n} catch (err) {\n  try { importDb.exec(''ROLLBACK''); } catch {}\n  try { importDb.exec(''PRAGMA foreign_keys = ON''); } catch {}\n  console.error(`Import failed: ${err.message}`);\n  process.exit(1);\n}\n\nfunction replaceAll(str, search, replacement) {\n  if (!search) return str;\n  return str.split(search).join(replacement);\n}","lineStart":1,"lineEnd":112,"totalLines":112,"truncated":false}},"title":"BaiduSyncdisk\\all_code\\candywall-skills\\conversation-backup\\scripts\\import_conversations.js","time":{"start":1783855094776,"end":1783855094786}}}'),
('prt_f560c9c9b0017ceJmEHVx2VtG3', 'msg_f560c8b35001XNZAaIn9aQgpDD', 'ses_0a9fbb56effeQaZdXvhiM6xltc', 1783855094939, 1783855094940, '{"reason":"tool-calls","type":"step-finish","tokens":{"total":12153,"input":1360,"output":153,"reasoning":16,"cache":{"write":0,"read":10624}},"cost":0.0017182}'),
('prt_f560ca31d001mdFxtFOEOQ456R', 'msg_f560c9c9f001X4pto6cm5jRLat', 'ses_0a9fbb56effeQaZdXvhiM6xltc', 1783855096605, 1783855096606, '{"type":"step-start"}'),
('prt_f560ca31e001iLosPZECm3x09y', 'msg_f560c9c9f001X4pto6cm5jRLat', 'ses_0a9fbb56effeQaZdXvhiM6xltc', 1783855096607, 1783855097293, '{"type":"reasoning","text":"Now I have a good understanding of the skill. Let me create two README files: README.md (English) and README.zh-CN.md (Chinese).","time":{"start":1783855096606,"end":1783855097292}}'),
('prt_f560ca5ce001NwjY0BAHl0m3xl', 'msg_f560c9c9f001X4pto6cm5jRLat', 'ses_0a9fbb56effeQaZdXvhiM6xltc', 1783855097294, 1783855111372, '{"type":"tool","tool":"write","callID":"call_d882ae7e8e38428d9505428d","state":{"status":"completed","input":{"content":"# opencode-conversation-sync\n\nAn [OpenCode](https://opencode.ai) skill for backing up and restoring conversation history across devices.\n\n## What it does\n\nExports your OpenCode conversation data (sessions, messages, parts, todos, etc.) as a SQL file, which lives in your project''s `.opencode/` directory and can be tracked by Git. Import the SQL on another device to restore your full conversation history.\n\n## Features\n\n- Export all conversations for the current project to a single SQL file\n- Import conversations with `INSERT OR REPLACE` (safe, idempotent)\n- Path & project ID are stored as placeholders (`{{WORKTREE}}`, `{{PROJECT_ID}}`) and auto-resolved on import\n- Automatic branch isolation — backup/restore runs on a dedicated `conversations-backup` branch to keep your working branch clean\n- Zero dependencies — uses Node.js 22+ built-in `node:sqlite`\n\n## Installation\n\nCopy the `SKILL.md` and `scripts/` directory into your OpenCode skills folder:\n\n```\n# Windows\n%USERPROFILE%\\.claude\\skills\\conversation-backup\\\n\n# macOS / Linux\n~/.claude/skills/conversation-backup/\n```\n\nOr register it in your project''s `opencode.json`:\n\n```json\n{\n  \"skills\": [\n    { \"path\": \"path/to/conversation-backup/SKILL.md\" }\n  ]\n}\n```\n\n## Usage\n\n### Backup\n\nIn a **new** OpenCode session, say:\n\n> 对话备份\n\nThe skill will:\n1. Verify this is a fresh session (to avoid exporting the backup command itself)\n2. Switch to the `conversations-backup` branch\n3. Export all conversations to `.opencode/conversations.sql`\n4. Commit and push to remote\n5. Switch back to your original branch\n\n### Restore\n\nIn a **new** OpenCode session, say:\n\n> 对话导入\n\nThe skill will:\n1. Verify this is a fresh session\n2. Switch to the `conversations-backup` branch\n3. Run a dry-run preview showing record counts\n4. Ask for confirmation, then execute the import\n5. Switch back to your original branch\n\n## Prerequisites\n\n- **Node.js 22+** (uses built-in `node:sqlite`, no `npm install` needed)\n- The project must be a Git repository with a remote configured\n- OpenCode database at `~/.local/share/opencode/opencode.db`\n\n## File Structure\n\n```\n├── SKILL.md                          # Skill definition\n└── scripts/\n    ├── check_session.js              # Verify fresh session\n    ├── export_conversations.js       # Export conversations to SQL\n    └── import_conversations.js       # Import conversations from SQL\n```\n\n## How it works\n\n1. **Export** reads the local `opencode.db` SQLite database, extracts all data for the current project (matched by working directory), replaces absolute paths and project IDs with placeholders, and writes `INSERT` statements to `.opencode/conversations.sql`.\n2. **Import** reads the SQL file, replaces placeholders with the local device''s actual paths and project ID, then executes the statements with `INSERT OR REPLACE` inside a transaction.\n3. Cross-device matching is done via Git remote URL — the same repo on different machines is recognized as the same project.\n\n## License\n\nMIT\n","filePath":"{{WORKTREE}}\\README.md"},"output":"Wrote file successfully.","metadata":{"diagnostics":{},"filepath":"{{WORKTREE}}\\README.md","exists":false,"truncated":false},"title":"BaiduSyncdisk\\all_code\\candywall-skills\\conversation-backup\\README.md","time":{"start":1783855111366,"end":1783855111371}}}'),
('prt_f560cdd2b0016PA0qlyHqMbt6X', 'msg_f560c9c9f001X4pto6cm5jRLat', 'ses_0a9fbb56effeQaZdXvhiM6xltc', 1783855111467, 1783855126035, '{"type":"tool","tool":"write","callID":"call_cd6449aa04f841598dc3c1d0","state":{"status":"completed","input":{"content":"# opencode-conversation-sync\n\n一个 [OpenCode](https://opencode.ai) 技能，用于在不同设备间备份和恢复对话记录。\n\n## 功能说明\n\n将 OpenCode 的对话数据（会话、消息、内容片段、待办事项等）导出为 SQL 文件，存放在项目的 `.opencode/` 目录下，可通过 Git 进行版本管理。在另一台设备上导入该 SQL 文件即可恢复完整的对话历史。\n\n## 特性\n\n- 将当前项目的所有对话导出为单个 SQL 文件\n- 使用 `INSERT OR REPLACE` 导入（幂等、安全）\n- 路径和项目 ID 以占位符（`{{WORKTREE}}`、`{{PROJECT_ID}}`）存储，导入时自动替换\n- 自动分支隔离 — 备份/恢复在独立的 `conversations-backup` 分支上执行，不污染工作分支\n- 零依赖 — 使用 Node.js 22+ 内置 `node:sqlite` 模块\n\n## 安装\n\n将 `SKILL.md` 和 `scripts/` 目录复制到 OpenCode 技能目录：\n\n```\n# Windows\n%USERPROFILE%\\.claude\\skills\\conversation-backup\\\n\n# macOS / Linux\n~/.claude/skills/conversation-backup/\n```\n\n或在项目的 `opencode.json` 中注册：\n\n```json\n{\n  \"skills\": [\n    { \"path\": \"path/to/conversation-backup/SKILL.md\" }\n  ]\n}\n```\n\n## 使用方法\n\n### 备份\n\n在一个**新的** OpenCode 对话中说：\n\n> 对话备份\n\n技能将：\n1. 验证当前为新会话（避免将备份操作本身的数据导出）\n2. 切换到 `conversations-backup` 分支\n3. 将所有对话导出到 `.opencode/conversations.sql`\n4. 提交并推送到远程仓库\n5. 切换回原来的分支\n\n### 恢复\n\n在一个**新的** OpenCode 对话中说：\n\n> 对话导入\n\n技能将：\n1. 验证当前为新会话\n2. 切换到 `conversations-backup` 分支\n3. 执行 dry-run 预览，展示各表记录数\n4. 询问确认后执行导入\n5. 切换回原来的分支\n\n## 前置条件\n\n- **Node.js 22+**（使用内置 `node:sqlite`，无需 `npm install`）\n- 项目必须是 Git 仓库且已配置远程仓库\n- OpenCode 数据库位于 `~/.local/share/opencode/opencode.db`\n\n## 文件结构\n\n```\n├── SKILL.md                          # 技能定义文件\n└── scripts/\n    ├── check_session.js              # 验证是否为新会话\n    ├── export_conversations.js       # 导出对话到 SQL\n    └── import_conversations.js       # 从 SQL 导入对话\n```\n\n## 工作原理\n\n1. **导出**：读取本地 `opencode.db` SQLite 数据库，提取当前项目（按工作目录匹配）的所有数据，将绝对路径和项目 ID 替换为占位符，将 `INSERT` 语句写入 `.opencode/conversations.sql`。\n2. **导入**：读取 SQL 文件，将占位符替换为本机实际路径和项目 ID，在事务中使用 `INSERT OR REPLACE` 执行语句。\n3. 跨设备识别通过 Git 远程仓库 URL 完成 — 不同机器上的同一仓库会被识别为同一项目。\n\n## 许可证\n\nMIT\n","filePath":"{{WORKTREE}}\\README.zh-CN.md"},"output":"Wrote file successfully.","metadata":{"diagnostics":{},"filepath":"{{WORKTREE}}\\README.zh-CN.md","exists":false,"truncated":false},"title":"BaiduSyncdisk\\all_code\\candywall-skills\\conversation-backup\\README.zh-CN.md","time":{"start":1783855126026,"end":1783855126035}}}'),
